```cpp
#include <hexi/hexi.h>
#include <vector>
#include <string>
#include <cstdint>
#include <span>

struct NetworkPacket {
    uint32_t packet_id;
    std::string username;
    std::vector<uint32_t> scores;
    std::string metadata;
};

NetworkPacket deserialize_packet(const std::span<const uint8_t> buffer) {
    // Create buffer_adaptor from the input buffer
    hexi::buffer_adaptor<const uint8_t> adaptor(buffer);

    NetworkPacket packet;

    // Read packet_id using read function
    adaptor.read(&packet.packet_id);

    // Read username using prefixed<std::string> adaptor
    std::string username;
    adaptor >> hexi::prefixed(username);
    packet.username = std::move(username);

    // Read scores vector: first read count, then use read_container
    uint32_t score_count;
    adaptor.read(&score_count);

    // Read container using read_container function
    packet.scores.resize(score_count);
    hexi::read_container(adaptor, packet.scores);

    // Read metadata string using null_terminated<std::string> adaptor
    std::string metadata;
    adaptor >> hexi::null_terminated(metadata);
    packet.metadata = std::move(metadata);

    // Skip any remaining padding bytes
    adaptor.skip(adaptor.size());

    return packet;
}

struct PacketInfo {
    uint32_t packet_id;
    std::string_view username;
};

PacketInfo extract_packet_info(const std::span<const uint8_t> buffer) {
    PacketInfo info;

    // Create buffer_adaptor from the input buffer
    hexi::buffer_adaptor<const uint8_t> adaptor(buffer);

    // Use span() to get zero-copy view of packet_id
    auto id_span = adaptor.span<uint32_t>(1);
    info.packet_id = id_span[0];

    // Read username using prefixed<std::string_view> adaptor
    adaptor >> hexi::prefixed(info.username);

    // Read scores count and skip the scores vector
    uint32_t score_count;
    adaptor.read(&score_count);

    // Skip the scores vector data
    adaptor.skip(score_count * sizeof(uint32_t));

    return info;
}
```

