struct PacketHeader {
    uint32_t magic;
    uint16_t version;
    uint16_t flags;
};

PacketHeader read_header_with_span(const std::span<const uint8_t> buffer) {
    // Create a buffer_adaptor from the input span
    hexi::buffer_adaptor<std::span<const uint8_t>> adaptor(buffer);

    // Use buffer_adaptor's read_ptr() to get the current read pointer
    const uint8_t* read_pointer = adaptor.read_ptr();

    // Check if there's enough data for the header using buffer_adaptor's size()
    if (adaptor.size() < sizeof(PacketHeader)) {
        // Not enough data for complete header
        return PacketHeader{};
    }

    // Use binary_stream's span() method to get a view of the header data
    hexi::binary_stream<decltype(adaptor)> stream(adaptor);
    auto header_span = stream.span<PacketHeader>(1);

    // Deserialize the header fields from the span
    PacketHeader header;
    if (!header_span.empty()) {
        header.magic = *reinterpret_cast<const uint32_t*>(header_span[0]);
        header.version = *reinterpret_cast<const uint16_t*>(header_span[0] + sizeof(uint32_t));
        header.flags = *reinterpret_cast<const uint16_t*>(header_span[0] + sizeof(uint32_t) + sizeof(uint16_t));
    }

    return header;
}

