```cpp
#include <hexi/allocators/block_allocator.h>
#include <cstdint>
#include <iostream>
#include <vector>

template<size_t element_count = 10>
void demonstrate_block_allocator_behavior() {
    // Create a block_allocator instance with uint64_t type
    hexi::block_allocator<uint64_t, element_count> allocator;

    std::cout << "=== Block Allocator Demonstration ===" << std::endl;
    std::cout << "Initial state: " << element_count << " blocks pre-allocated" << std::endl;

    // Demonstrate allocation sequence
    std::vector<uint64_t*> allocated_blocks;

    // First allocation - takes from pre-allocated storage
    uint64_t* block1 = allocator.allocate();
    allocated_blocks.push_back(block1);
    std::cout << "1. Allocated block1 from pre-allocated storage" << std::endl;

    // Second allocation - also from pre-allocated storage
    uint64_t* block2 = allocator.allocate();
    allocated_blocks.push_back(block2);
    std::cout << "2. Allocated block2 from pre-allocated storage" << std::endl;

    // Third allocation - from pre-allocated storage
    uint64_t* block3 = allocator.allocate();
    allocated_blocks.push_back(block3);
    std::cout << "3. Allocated block3 from pre-allocated storage" << std::endl;

    std::cout << "\n=== Free List Management Demonstration ===" << std::endl;

    // Deallocate block3 - this calls push() to add to free list head
    allocator.deallocate(block3);
    std::cout << "4. Deallocated block3 → push() adds to free list head" << std::endl;

    // Deallocate block2 - push() adds to free list head (now second position)
    allocator.deallocate(block2);
    std::cout << "5. Deallocated block2 → push() adds to free list head" << std::endl;

    // Fourth allocation - pop() retrieves from free list (should get block2 first)
    uint64_t* block4 = allocator.allocate();
    allocated_blocks.push_back(block4);
    std::cout << "6. Allocated block4 → pop() retrieves from free list (LIFO order)" << std::endl;

    // Fifth allocation - pop() retrieves next from free list (should get block3)
    uint64_t* block5 = allocator.allocate();
    allocated_blocks.push_back(block5);
    std::cout << "7. Allocated block5 → pop() retrieves next from free list" << std::endl;

    // Continue demonstrating the LIFO behavior...
    std::cout << "\n=== Final State ===" << std::endl;
    std::cout << "Allocated blocks count: " << allocated_blocks.size() << std::endl;
    std::cout << "Free list now contains remaining pre-allocated blocks" << std::endl;

    // Clean up all allocated blocks
    for (auto* block : allocated_blocks) {
        allocator.deallocate(block);
    }
}

int main() {
    demonstrate_block_allocator_behavior<5>(); // Use smaller count for clearer demonstration
    return 0;
}
```

## Key Points Demonstrated:

1. **Constructor Behavior**: The allocator starts with `element_count` blocks pre-allocated in the storage array
2. **Initial Allocation**: First few allocations come from the pre-allocated storage (`storage_.data()`)
3. **Free List Management**: 
   - `deallocate()` calls `push()` which adds blocks to the **head** of the free list
   - `allocate()` calls `pop()` which removes from the **head** (LIFO behavior)
4. **Memory Reuse Pattern**: Deallocated blocks are reused in reverse order (last deallocated becomes first reallocated)
5. **Thread Safety**: The allocator includes thread ID validation when using `validate_dealloc` policy

## Expected Output:
```
=== Block Allocator Demonstration ===
Initial state: 5 blocks pre-allocated
1. Allocated block1 from pre-allocated storage
2. Allocated block2 from pre-allocated storage
3. Allocated block3 from pre-allocated storage

=== Free List Management Demonstration ===
4. Deallocated block3 → push() adds to free list head
5. Deallocated block2 → push() adds to free list head
6. Allocated block4 → pop() retrieves from free list (LIFO order)
7. Allocated block5 → pop() retrieves next from free list

=== Final State ===
Allocated blocks count: 5
Free list now contains remaining pre-allocated blocks
```

This implementation clearly shows how the `push()` and `pop()` methods manage the free list as a LIFO stack, with deallocated blocks being added to the head and reallocated blocks being taken from the head.

