```cpp
#include <hexi/hexi.h>
#include <hexi/endian.h>
#include <vector>
#include <cstdint>
#include <string>
#include <string_view>

struct MeasurementData {
    uint32_t sensor_id;
    std::vector<float> temperatures;
    double pressure;

    void serialise(auto& adaptor) const {
        // Serialize sensor_id directly
        adaptor.write(sensor_id);

        // Convert and write each temperature with runtime endianness conversion
        for (float temp : temperatures) {
            float converted_temp = hexi::endian::conditional_reverse<std::endian::native, std::endian::little>(temp);
            adaptor.write(converted_temp);
        }

        // Convert and write pressure with runtime endianness conversion
        double converted_pressure = hexi::endian::conditional_reverse<std::endian::native, std::endian::little>(pressure);
        adaptor.write(converted_pressure);
    }

    void serialise(auto& adaptor) {
        // Deserialize sensor_id directly
        adaptor.read(sensor_id);

        // Read and convert each temperature using in-place conversion
        temperatures.clear();
        for (size_t i = 0; i < temperatures.size(); ++i) {
            float temp;
            adaptor.read(temp);
            hexi::endian::little_to_native_inplace(temp);
            temperatures.push_back(temp);
        }

        // Read and convert pressure using in-place conversion
        double p;
        adaptor.read(p);
        hexi::endian::little_to_native_inplace(p);
        pressure = p;
    }
};

std::vector<uint8_t> serialize_measurement_data(const MeasurementData& data) {
    std::vector<uint8_t> buffer;
    hexi::buffer_adaptor adaptor(buffer);
    hexi::stream stream(adaptor);

    stream.serialise(data);
    return buffer;
}

MeasurementData deserialize_measurement_data(const std::span<const uint8_t> buffer) {
    std::vector<uint8_t> vec_buffer(buffer.begin(), buffer.end());
    hexi::buffer_adaptor adaptor(vec_buffer);
    hexi::stream stream(adaptor);

    MeasurementData data;
    stream.deserialise(data);
    return data;
}

struct SensorInfo {
    uint32_t sensor_id;
    std::string_view sensor_name;
};

SensorInfo extract_sensor_info(const std::span<const uint8_t> buffer) {
    std::vector<uint8_t> vec_buffer(buffer.begin(), buffer.end());
    hexi::buffer_adaptor adaptor(vec_buffer);
    hexi::stream stream(adaptor);

    SensorInfo info;

    // Extract sensor name using view (null-terminated string)
    info.sensor_name = stream.view();

    // Check if there's enough data for sensor_id using enforce_read_bounds
    stream.enforce_read_bounds(sizeof(uint32_t));

    // Read sensor_id directly
    stream.read(&info.sensor_id);

    // Skip remaining data using skip
    // Calculate remaining data size: total buffer size minus what we've already read
    size_t remaining_size = vec_buffer.size() - stream.total_read();
    if (remaining_size > 0) {
        stream.skip(remaining_size);
    }

